function worked_http_ts_performance_release_defense_4(p95Ms: number, latencyBudgetMs: number, queueDepth: number, queueCapacity: number): { release: boolean; saturated: boolean } {
  if (p95Ms < 0 || latencyBudgetMs <= 0 || queueDepth < 0 || queueCapacity <= 0) {
    return { release: false, saturated: true };
  }
  const saturated = queueDepth >= queueCapacity;
  return { release: p95Ms <= latencyBudgetMs && !saturated, saturated };
}

